const data = $node["Webhook"].json.body;

// ── 1. RAW CONTEXT FROM SUPABASE ──────────────────────────────────
const pd           = data.profile || {};
const memories     = data.memories || [];
const assessments  = data.assessments || [];
const activeTasks  = data.recent_tasks_assigned || [];
const caseNotes    = data.recent_case_notes || [];
const messages     = data.messages || [];

const coachPrompt  = data.coach_prompt  || 'You are an empathetic, non-judgmental mental health coach.';
const phasePrompt  = data.phase_prompt  || 'Focus on building therapeutic rapport and gathering clinical context.';
const pathway      = data.pathway       || 'engagement_rapport_and_assessment';
const theme        = data.dynamic_theme || 'Not yet identified';
const messageCount = data.message_count || 1;
const currentPhase = data.journey_context?.current_phase || 1;
const profileId    = data.profile_id    || '';
const sessionId    = data.session_id    || '';
const isGreeting   = data.is_system_greeting || false;

// ── 2. STRINGIFY CONTEXT SECTIONS ────────────────────────────────
const personalDetails = [
  `Name: ${pd.name || 'Unknown'}`,
  `Age: ${pd.age || 'Unknown'}`,
  `Gender: ${pd.gender || 'Unknown'}`,
  `Presenting Concerns: ${(pd.concerns || []).join(', ') || 'Not specified'}`,
].join('\n');

const memoriesStr = memories.length
  ? memories.map(m => `  [${(m.type || 'fact').toUpperCase()}] ${m.text}`).join('\n')
  : '  None recorded yet.';

const assessmentsStr = assessments.length
  ? assessments.map(a => `  ${a.assessment_type}: ${a.score} (${new Date(a.created_at).toLocaleDateString()})`).join('\n')
  : '  No formal assessments completed yet.';

const tasksStr = activeTasks.length
  ? activeTasks.map(t => `  - ${t.dynamic_title || t.task_name} (${t.task_frequency})\n    -> ${t.dynamic_description || t.task_description}`).join('\n')
  : '  No active homework assigned.';

const notesStr = caseNotes.length
  ? caseNotes.map((n, i) => `  Session -${i+1}: Concern: "${n.presenting_concern}" | Progress: ${n.phase_progress} | Readiness: ${n.readiness_for_next_phase}`).join('\n')
  : '  No prior session notes.';

const transcript = messages.slice(-20)
  .map(m => `  ${m.role === 'user' ? 'Client' : 'Therapist'}: ${m.content}`)
  .join('\n');

// ── 3. PACING / OVERRIDE INSTRUCTION ─────────────────────────────
// Priority order: highest turn threshold first (50 > 24 > 18 > 15 > 13)
let pacingInstruction = '';
let shouldRunDiscovery = false;

if (isGreeting) {
  // GREETING — first message of the session
  pacingInstruction = `\n[GREETING]\nThis is the very first message of the session. Generate a warm, personalised opening greeting.\n- Address the client by name (${pd.name || 'there'}).\n- Briefly reflect their stated concerns (${(pd.concerns || []).join(', ')}) back with empathy and warmth.\n- If this is a returning session, reference a relevant memory or past session theme.\n- Do NOT ask a question yet — just make them feel heard and welcome.\n- Set is_session_close to false.`;
} else if (messageCount >= 50) {
  // HARD CLOSE — extended session
  pacingInstruction = `\n[EXTENDED SESSION OVERRIDE — TURN ${messageCount}]\nThis session has exceeded 50 messages. You MUST bring this session to a close within 2-3 messages maximum.\nUse the session-close phrase: "I'm really glad we took this time together today, ${pd.name || 'there'}. You've shared something really important. I'll carry this with you into our next conversation. Take good care of yourself. 💙"\nSet is_session_close to true in your JSON response.`;
} else if (messageCount >= 24) {
  // SOFT CLOSE — use closing phrase
  pacingInstruction = `\n[SESSION CLOSING — TURN ${messageCount}]\nThis session is at its natural closing point. Use your session-close phrase now:\n"I'm really glad we took this time together today, ${pd.name || 'there'}. You've shared something really important. Before you go — I'd love for you to try [mention a relevant task] this week. Take good care of yourself. 💙"\nSet is_session_close to true in your JSON response.`;
} else if (messageCount >= 18) {
  // SYNTHESIS — begin wrapping up
  pacingInstruction = `\n[SYNTHESIS PHASE — TURN ${messageCount}]\nBegin transitioning toward a closing insight. Help the client articulate one small, concrete Takeaway Task rooted in Phase ${currentPhase}'s therapeutic goals.\nDo NOT close yet. Set is_session_close to false.`;
} else if (pathway === 'engagement_rapport_and_assessment' && messageCount >= 15 && messageCount % 5 === 0) {
  // PATHWAY CHECK — runs at turns 15, 20, 25, 30...
  pacingInstruction = `\n[SYSTEM OVERRIDE - PATHWAY DECISION REQUIRED — TURN ${messageCount}]\nYou have gathered ${messageCount} messages of exploratory context. It is now clinically appropriate to move toward a pathway decision.\nBased on everything shared, identify the 2 most clinically relevant pathways from the 20 available options.\nPresent them warmly and collaboratively to the client. Ask which resonates more. Avoid clinical jargon.\nSet is_session_close to false.`;
  shouldRunDiscovery = true;
} else if (messageCount >= 13) {
  // PRE-SYNTHESIS
  pacingInstruction = `\n[SYNTHESIS PHASE — TURN ${messageCount}]\nBegin transitioning toward a closing insight. Help the client articulate one small, concrete Takeaway Task rooted in Phase ${currentPhase}'s therapeutic goals.\nSet is_session_close to false.`;
}

// Discovery Agent should also run on every 5th turn during assessment for background classification
if (pathway === 'engagement_rapport_and_assessment' && messageCount >= 15 && messageCount % 5 === 0) {
  shouldRunDiscovery = true;
}

// ── 4. FINAL ASSEMBLED SYSTEM PROMPT ─────────────────────────────
const systemPrompt = `${coachPrompt}\n\n${phasePrompt}\n\n[CLIENT PROFILE]\n${personalDetails}\n\n[CURRENT CLINICAL THEME]\n${theme}\n\n[ASSESSMENT SCORES]\n${assessmentsStr}\n\n[ACTIVE HOMEWORK / TASKS ASSIGNED]\n${tasksStr}\n\n[PAST SESSION CASE NOTES]\n${notesStr}\n\n[LONG-TERM MEMORIES]\n${memoriesStr}\n\n[SESSION TRANSCRIPT (last 20 messages)]\n${transcript}\n\n[INSTRUCTIONS]\n- Respond in ONE empathetic, conversational message. Never bullet points, never clinical language.\n- You MUST acknowledge the client's last statement before moving forward.\n- If the client has active tasks above, naturally check in on their progress before moving to new topics.\n- You may inject ONE dynamic tool per message if clinically warranted:\n    Grounding game: 'box_breathing' or 'senses_54321' -> use if client shows acute panic/distress\n    Video: 'meditation_sleep' or 'somatic_tension' -> use if client mentions poor sleep or physical tension\n    Assessment: 'gad7' | 'phq9' | 'pss4' -> use if a matching condition is mentioned and not recently assessed\n    Do NOT inject tools in every message. Only when genuinely clinically useful.\n\n[is_session_close FIELD]\nYour output has an is_session_close boolean field. Set it to true ONLY when you use the session-close phrase to end the session. Otherwise always set it to false.\n${pacingInstruction}\n\n[MEMORY TOOL]\nYou have access to a 'Save Memory' Postgres tool. Use it to INSERT a new row into the mind_coach_memories table whenever the client reveals an important, persistent fact about themselves that should be remembered long-term across sessions.\nExamples of what to save: triggers, coping strategies, relationships, goals, preferences, significant life events.\nDo NOT save: transient emotions, session logistics, or things already in the memories list above.\nWhen saving, use profile_id='${profileId}' and session_id='${sessionId}'.\n\nYou must return a structured JSON response.`;

return [{ json: { systemPrompt, userMessage: data.message_text || '', profileId, sessionId, shouldRunDiscovery, messageCount } }];

