// Grab the Therapist Agent's parsed output
const therapistOutput = $node["Therapist Agent"].json.output || {};

const finalResponse = {
  reply: therapistOutput.reply || '',
  is_session_close: therapistOutput.is_session_close || false,
  guardrail_status: 'passed',
  crisis_detected: false
};

// Only include dynamic_content if structurally valid
if (therapistOutput.dynamic_content?.type && therapistOutput.dynamic_content?.payload) {
  finalResponse.dynamic_content = therapistOutput.dynamic_content;
}

// Merge Discovery Agent output if it ran (assessment phase only)
try {
  const discoveryOutput = $node["Discovery Agent"].json.output || {};
  if (discoveryOutput.suggested_pathway) {
    finalResponse.dynamic_theme      = discoveryOutput.dynamic_theme;
    finalResponse.suggested_pathway  = discoveryOutput.suggested_pathway;
    finalResponse.pathway_confidence = discoveryOutput.pathway_confidence;
  }
} catch (e) {
  // Non-assessment pathway: no discovery fields needed
}

return [{ json: finalResponse }];
